mapper.select:
SELECT id, username, session_id AS sessionId, intent, model,
       prompt_tokens AS promptTokens, completion_tokens AS completionTokens,
       total_tokens AS totalTokens, tool_calls AS toolCalls,
       latency_ms AS latencyMs, create_time AS createTime
FROM ums_token_usage


        AND username = #{username}


        AND intent = #{intent}


        AND create_time >= #{startDate}


        AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)


ORDER BY create_time DESC

SELECT COUNT(*)
FROM ums_token_usage


        AND username = #{username}


        AND intent = #{intent}


        AND create_time >= #{startDate}


        AND create_time < DATE_ADD(#{endDate}, INTERVAL 1 DAY)
